import{bV as s,aL as e,u as t,G as i}from"./chunks/framework.D_inzUUb.js";const c=JSON.parse('{"title":"Ookla Speedtest 在 Ubuntu 24.04 安装失败的解决办法","description":"","frontmatter":{"title":"Ookla Speedtest 在 Ubuntu 24.04 安装失败的解决办法","date":"2025-01-19T00:00:00.000Z","categories":["Linux"],"tags":["Ubuntu","Speedtest","网络工具"]},"headers":[],"relativePath":"posts/202501/19-ookla-speedtest-ubuntu24.md","filePath":"posts/202501/19-ookla-speedtest-ubuntu24.md","lastUpdated":1777767919000}'),l={name:"posts/202501/19-ookla-speedtest-ubuntu24.md"};function n(h,a,p,o,d,r){return e(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="ookla-speedtest-在-ubuntu-24-04-安装失败的解决办法" tabindex="-1">Ookla Speedtest 在 Ubuntu 24.04 安装失败的解决办法 <a class="header-anchor" href="#ookla-speedtest-在-ubuntu-24-04-安装失败的解决办法" aria-label="Permalink to &quot;Ookla Speedtest 在 Ubuntu 24.04 安装失败的解决办法&quot;">​</a></h1><p>Ubuntu 24.04 (Noble) 下通过 apt 安装 Ookla Speedtest CLI 时可能会失败，因为官方源尚未适配 Noble 版本。解决方法是将源中的 <code>noble</code> 替换为 <code>jammy</code>。</p><h2 id="解决步骤" tabindex="-1">解决步骤 <a class="header-anchor" href="#解决步骤" aria-label="Permalink to &quot;解决步骤&quot;">​</a></h2><h3 id="_1-安装依赖" tabindex="-1">1. 安装依赖 <a class="header-anchor" href="#_1-安装依赖" aria-label="Permalink to &quot;1. 安装依赖&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span></span></code></pre></div><h3 id="_2-添加-ookla-软件源" tabindex="-1">2. 添加 Ookla 软件源 <a class="header-anchor" href="#_2-添加-ookla-软件源" aria-label="Permalink to &quot;2. 添加 Ookla 软件源&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://packagecloud.io/install/repositories/ookla/speedtest-cli/script.deb.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre></div><h3 id="_3-替换发行版代号" tabindex="-1">3. 替换发行版代号 <a class="header-anchor" href="#_3-替换发行版代号" aria-label="Permalink to &quot;3. 替换发行版代号&quot;">​</a></h3><p>编辑源文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/apt/sources.list.d/ookla_speedtest-cli.list</span></span></code></pre></div><p>将其中的 <code>noble</code> 替换为 <code>jammy</code>，保存退出。</p><h3 id="_4-安装-speedtest" tabindex="-1">4. 安装 Speedtest <a class="header-anchor" href="#_4-安装-speedtest" aria-label="Permalink to &quot;4. 安装 Speedtest&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> speedtest</span></span></code></pre></div><h3 id="_5-运行测试" tabindex="-1">5. 运行测试 <a class="header-anchor" href="#_5-运行测试" aria-label="Permalink to &quot;5. 运行测试&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">speedtest</span></span></code></pre></div><h2 id="原因说明" tabindex="-1">原因说明 <a class="header-anchor" href="#原因说明" aria-label="Permalink to &quot;原因说明&quot;">​</a></h2><p>Ookla 的 packagecloud 仓库在 Ubuntu 24.04 (Noble) 发布时还没有提供对应的包，使用 22.04 (Jammy) 的包可以正常兼容运行。</p><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://support.ookla.com/hc/en-us/articles/32139787616141-Ubuntu-24-04-noble" target="_blank" rel="noreferrer">Ookla 官方解决方案 - Ubuntu 24.04 Noble</a></li><li><a href="https://www.speedtest.net/apps/cli" target="_blank" rel="noreferrer">Ookla Speedtest CLI 官网</a></li></ul>`,19)])])}const u=s(l,[["render",n]]);export{c as __pageData,u as default};
